package com.example.socialmediacampaignagentsprintboot.agent;import com.example.socialmediacampaignagentsprintboot.model.ContentPillar;import com.example.socialmediacampaignagentsprintboot.model.FunnelStage;import com.example.socialmediacampaignagentsprintboot.model.Platform;import dev.langchain4j.service.MemoryId;import dev.langchain4j.service.SystemMessage;import dev.langchain4j.service.UserMessage;import dev.langchain4j.service.V;/** * Represents an AI-powered Copywriter Agent designed to generate, rewrite, and revise * social media posts tailored to specific platforms, audience types, and marketing objectives. * It leverages strategic inputs such as content pillars and funnel stages to produce effective * and engaging content aligned with platform-specific guidelines. * * Responsibilities: * - Generate original social media posts based on strategic inputs. * - Rewrite posts that fail to meet quality standards based on provided feedback. * - Revise drafts based on explicit human-provided editing instructions, adhering to platform *   constraints and style guidelines. * * Functional Overview: * 1. LinkedIn: *    - Professional and engaging tone. *    - Posts must be between 500-1500 characters. * 2. X: *    - Casual and punchy tone. *    - Strict character limit of 280, with a preference for below 200 characters. * * Methods: * - `writePost`: Creates a platform-specific social media post using strategic directives. * - `rewritePost`: Revises a rejected draft, addressing specific reviewer feedback. * - `revisePost`: Edits current drafts based on detailed human editing instructions. */public interface CopywriterAgent {    @UserMessage("""        [BLACKBOARD CONTEXT]:        {{campaignContext}}                Directive:        Write the initial draft for this post based on the strategy in the context above.        """)    String writePost(@MemoryId String memoryId, @V("campaignContext") String campaignContext);    @UserMessage("""        The following draft you wrote was REJECTED by the quality assurance reviewer.        [BLACKBOARD CONTEXT]        {{campaignContext}}                [REJECTED DRAFT]:        {{previousDraft}}                [REVIEWER FEEDBACK]:        {{feedback}}        Please rewrite the post to fix these exact issues while strictly adhering to the Blackboard Context.        Remember our previous conversation history if applicable.        Return ONLY the new post text.        """)    String rewritePost(@MemoryId String memoryId,                       @V("campaignContext") String campaignContext,                       @V("previousDraft") String previousDraft,                       @V("feedback") String feedback);}